import React from 'react';
import styled from 'styled-components';
import { useNavigate } from 'react-router-dom';
import { Button } from '../../components/Button';
import { useAuth } from '../../contexts/AuthContext';

const Container = styled.div`
  min-height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  position: relative;
  overflow: hidden;
`;

const BackgroundShape = styled.div`
  position: absolute;
  width: 100%;
  height: 100%;
  overflow: hidden;
  
  &::before {
    content: '';
    position: absolute;
    top: -50%;
    left: -50%;
    width: 200%;
    height: 200%;
    background: radial-gradient(circle, rgba(255,255,255,0.1) 1px, transparent 1px);
    background-size: 50px 50px;
    animation: moveBackground 20s linear infinite;
  }
  
  @keyframes moveBackground {
    0% {
      transform: translate(0, 0);
    }
    100% {
      transform: translate(50px, 50px);
    }
  }
`;

const Content = styled.div`
  max-width: 500px;
  width: 100%;
  text-align: center;
  background-color: rgba(255, 255, 255, 0.95);
  border-radius: 32px;
  padding: 48px 40px;
  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.25);
  backdrop-filter: blur(10px);
  z-index: 10;
  transition: transform 0.3s ease;
  
  &:hover {
    transform: translateY(-5px);
  }
`;

const Title = styled.h1`
  font-size: 2.8rem;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  margin-bottom: 16px;
  font-weight: 800;
  letter-spacing: -0.5px;
`;

const Subtitle = styled.p`
  color: #666;
  font-size: 1rem;
  margin-bottom: 32px;
`;

const TruckIcon = styled.div`
  font-size: 5rem;
  margin: 24px 0;
  animation: bounce 2s ease-in-out infinite;
  
  @keyframes bounce {
    0%, 100% {
      transform: translateY(0);
    }
    50% {
      transform: translateY(-10px);
    }
  }
`;

const ButtonContainer = styled.div`
  display: flex;
  gap: 16px;
  justify-content: center;
  flex-wrap: wrap;
  margin-top: 24px;
`;

const FeatureSection = styled.div`
  display: flex;
  justify-content: center;
  gap: 32px;
  margin-top: 48px;
  padding-top: 32px;
  border-top: 1px solid #eee;
`;

const Feature = styled.div`
  text-align: center;
  flex: 1;
  
  svg {
    font-size: 1.5rem;
    color: #667eea;
    margin-bottom: 8px;
  }
  
  span {
    font-size: 0.8rem;
    color: #666;
    display: block;
  }
`;

const DemoBadge = styled.div`
  margin-top: 32px;
  padding: 8px 16px;
  background-color: #f3f4f6;
  border-radius: 20px;
  font-size: 0.7rem;
  color: #666;
  display: inline-block;
`;

export const LandingPage = () => {
  const navigate = useNavigate();
  const { loginSimulado } = useAuth();

  const acessoRapido = () => {
    loginSimulado();
    navigate('/home');
  };

  return (
    <Container>
      <BackgroundShape />
      <Content>
        <TruckIcon>🚛</TruckIcon>
        <Title>Envelope Digital</Title>
        <Subtitle>Gerencie suas viagens de forma inteligente e organizada</Subtitle>
        
        <ButtonContainer>
          <Button onClick={() => navigate('/register')} large>
            Cadastrar
          </Button>
          <Button outline onClick={() => navigate('/login')} large>
            Login
          </Button>
        </ButtonContainer>
        
        <ButtonContainer>
          <Button 
            small 
            onClick={acessoRapido}
            style={{ background: '#10b981', borderColor: '#10b981' }}
          >
            🚀 Acesso Rápido (Demo)
          </Button>
        </ButtonContainer>
        
        <FeatureSection>
          <Feature>
            <div>📊</div>
            <span>Controle Financeiro</span>
          </Feature>
          <Feature>
            <div>📍</div>
            <span>Histórico de Viagens</span>
          </Feature>
          <Feature>
            <div>⚡</div>
            <span>Cálculos Automáticos</span>
          </Feature>
        </FeatureSection>
        
        <DemoBadge>
          🔧 Modo de demonstração - Explore todas as funcionalidades
        </DemoBadge>
      </Content>
    </Container>
  );
};
